def make_circle_avatar(b64_str, size):
    raw  = _b64.b64decode(b64_str)
    img  = Image.open(_io.BytesIO(raw)).convert("RGBA")
    w, h = img.size
    m    = min(w, h)
    img  = img.crop(((w-m)//2, (h-m)//2, (w-m)//2+m, (h-m)//2+m))
    img  = img.resize((size, size), Image.LANCZOS)
    mask = Image.new("L", (size, size), 0)
    ImageDraw.Draw(mask).ellipse((0, 0, size, size), fill=255)
    img.putalpha(mask)
    ring = Image.new("RGBA", (size, size), (0,0,0,0))
    ImageDraw.Draw(ring).ellipse((0,0,size-1,size-1), outline=(232,64,28,255), width=3)
    img  = Image.alpha_composite(img, ring)
    return ctk.CTkImage(light_image=img, dark_image=img, size=(size, size))


