def read_links(filepath):
    links = []
    ext = Path(filepath).suffix.lower()
    with open(filepath, "r", encoding="utf-8") as f:
        if ext == ".csv":
            import csv as _csv
            reader = _csv.DictReader(f)
            for row in reader:
                url = row.get("url", "").strip()
                if url:
                    links.append(url)
        else:
            for line in f:
                url = line.strip()
                if url and not url.startswith("#"):
                    links.append(url)
    return links


def is_downloading(download_dir):
    return any(
        f.endswith(".crdownload") or f.endswith(".part")
        for f in os.listdir(download_dir)
    )

def count_files(directory):
    return len([f for f in os.listdir(directory) if not f.endswith(".crdownload") and not f.endswith(".part")])

def wait_for_download(download_dir, timeout=120):
    start = time.time()
    time.sleep(3)          # give Chrome a moment to start the download
    while time.time() - start < timeout:
        if not is_downloading(download_dir):
            return True
        time.sleep(1)
    return False

def snapshot_files(download_dir):
    return {f for f in os.listdir(download_dir)
            if not f.endswith(".crdownload") and not f.endswith(".part")}


def build_driver(download_dir):
    download_dir = os.path.normpath(download_dir)
    
    os.makedirs(download_dir, exist_ok=True)
    options = Options()
    options.add_experimental_option("detach", True)
    options.add_experimental_option("prefs", {
        "download.default_directory": download_dir,
        "download.prompt_for_download": False,
        "download.directory_upgrade": True,
        "safebrowsing.enabled": True,
    })
    options.add_argument("--disable-popup-blocking")
    
    return webdriver.Chrome(
        service=Service(ChromeDriverManager().install()),
        options=options,
    )


def click_with_js(driver, element):
    driver.execute_script("arguments[0].click();", element)


def find_download_button(driver, timeout=20):
    selectors = [
        "button.link-button.gay-button",
        "button.link-button",
        "button.gay-button",
        (By.XPATH, "//button[contains(translate(.,'ABCDEFGHIJKLMNOPQRSTUVWXYZ','abcdefghijklmnopqrstuvwxyz'),'download')]"),
    ]
    for selector in selectors:
        try:
            if isinstance(selector, tuple):
                btn = WebDriverWait(driver, timeout).until(
                    EC.element_to_be_clickable(selector))
            else:
                btn = WebDriverWait(driver, timeout).until(
                    EC.element_to_be_clickable((By.CSS_SELECTOR, selector)))
            return btn
        except Exception:
            continue
    return None


